{
  "name": "EduVerify - K-12 Employment Verification Generator",
  "description": "Professional tool for generating US school employment verification letters with live preview, random sample data, and multi-format export."
}

export interface SchoolInfo {
  id: string;
  name: string;
  address: string;
  cityStateZip: string;
  phone: string;
  fax: string;
  district: string;
  mascot?: string;
  domain: string;
}

export interface TeacherData {
  firstName: string;
  lastName: string;
  title: string;
  prefix: 'Mr.' | 'Ms.' | 'Dr.' | 'Mrs.';
  emailPrefix: string;
}

export interface LetterConfig {
  date: string;
  school: SchoolInfo;
  teacher: TeacherData;
  principalName: string;
  principalPrefix: string;
  status: string;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Copy, Download, RefreshCw, Check, Mail, User, Building, MapPin, Calendar, Briefcase } from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { LetterConfig, SchoolInfo, TeacherData } from './types';
import { SCHOOL_PRESETS, TEACHER_POOL } from './constants';

const App: React.FC = () => {
  const [config, setConfig] = useState<LetterConfig>({
    date: new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }),
    school: SCHOOL_PRESETS[0],
    teacher: TEACHER_POOL[0],
    principalName: 'Elizabeth McNamara',
    principalPrefix: 'Dr.',
    status: 'Active, Full-Time'
  });

  const [usedIndices, setUsedIndices] = useState<Set<number>>(new Set([0]));
  const [copiedField, setCopiedField] = useState<string | null>(null);
  const letterRef = useRef<HTMLDivElement>(null);

  const handleRandomize = () => {
    let nextIndex: number;
    if (usedIndices.size >= TEACHER_POOL.length) {
      setUsedIndices(new Set());
      nextIndex = Math.floor(Math.random() * TEACHER_POOL.length);
    } else {
      do {
        nextIndex = Math.floor(Math.random() * TEACHER_POOL.length);
      } while (usedIndices.has(nextIndex));
    }

    setUsedIndices(prev => new Set(prev).add(nextIndex));
    setConfig(prev => ({
      ...prev,
      teacher: TEACHER_POOL[nextIndex]
    }));
  };

  const handleCopy = (text: string, fieldName: string) => {
    navigator.clipboard.writeText(text);
    setCopiedField(fieldName);
    setTimeout(() => setCopiedField(null), 2000);
  };

  const downloadPNG = async () => {
    if (!letterRef.current) return;
    const canvas = await html2canvas(letterRef.current, { scale: 2 });
    const link = document.createElement('a');
    link.download = `${config.teacher.firstName}_${config.teacher.lastName}_Verification.png`;
    link.href = canvas.toDataURL('image/png');
    link.click();
  };

  const downloadPDF = async () => {
    if (!letterRef.current) return;
    const canvas = await html2canvas(letterRef.current, { scale: 2 });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const imgProps = pdf.getImageProperties(imgData);
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;
    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`${config.teacher.firstName}_${config.teacher.lastName}_Verification.pdf`);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Sidebar Editor */}
      <div className="w-full md:w-96 bg-white shadow-xl p-6 overflow-y-auto max-h-screen border-r border-slate-200 sticky top-0">
        <div className="flex items-center gap-2 mb-8">
          <div className="bg-blue-600 p-2 rounded-lg">
            <Building className="text-white w-6 h-6" />
          </div>
          <h1 className="text-xl font-bold text-slate-800">EduVerify Pro</h1>
        </div>

        <div className="space-y-6">
          <section>
            <div className="flex justify-between items-center mb-4">
              <label className="text-sm font-semibold text-slate-500 uppercase tracking-wider">Teacher Details</label>
              <button 
                onClick={handleRandomize}
                className="flex items-center gap-1 text-xs font-medium text-blue-600 hover:text-blue-700 bg-blue-50 px-2 py-1 rounded transition-colors"
              >
                <RefreshCw className="w-3 h-3" /> Random Sample
              </button>
            </div>

            <div className="space-y-4">
              <div className="flex gap-2">
                <div className="w-20">
                  <label className="text-xs text-slate-400 block mb-1">Prefix</label>
                  <select 
                    value={config.teacher.prefix}
                    onChange={e => setConfig({ ...config, teacher: { ...config.teacher, prefix: e.target.value as any }})}
                    className="w-full border border-slate-200 rounded px-2 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  >
                    <option>Mr.</option>
                    <option>Ms.</option>
                    <option>Dr.</option>
                    <option>Mrs.</option>
                  </select>
                </div>
                <div className="flex-1">
                  <label className="text-xs text-slate-400 block mb-1">First Name</label>
                  <input 
                    type="text" 
                    value={config.teacher.firstName}
                    onChange={e => setConfig({ ...config, teacher: { ...config.teacher, firstName: e.target.value }})}
                    className="w-full border border-slate-200 rounded px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  />
                </div>
              </div>

              <div>
                <label className="text-xs text-slate-400 block mb-1">Last Name</label>
                <div className="relative group">
                  <input 
                    type="text" 
                    value={config.teacher.lastName}
                    onChange={e => setConfig({ ...config, teacher: { ...config.teacher, lastName: e.target.value }})}
                    className="w-full border border-slate-200 rounded px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  />
                  <button 
                    onClick={() => handleCopy(`${config.teacher.firstName} ${config.teacher.lastName}`, 'name')}
                    className="absolute right-2 top-2 p-1 text-slate-400 hover:text-blue-600 opacity-0 group-hover:opacity-100 transition-opacity"
                    title="Copy Full Name"
                  >
                    {copiedField === 'name' ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                </div>
              </div>

              <div>
                <label className="text-xs text-slate-400 block mb-1">Title</label>
                <input 
                  type="text" 
                  value={config.teacher.title}
                  onChange={e => setConfig({ ...config, teacher: { ...config.teacher, title: e.target.value }})}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>

              <div>
                <label className="text-xs text-slate-400 block mb-1">Email Prefix</label>
                <div className="relative group flex items-center">
                  <div className="flex-1 relative">
                    <input 
                      type="text" 
                      value={config.teacher.emailPrefix}
                      onChange={e => setConfig({ ...config, teacher: { ...config.teacher, emailPrefix: e.target.value }})}
                      className="w-full border border-slate-200 rounded-l px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                    <button 
                      onClick={() => handleCopy(`${config.teacher.emailPrefix}@${config.school.domain}`, 'email')}
                      className="absolute right-2 top-2 p-1 text-slate-400 hover:text-blue-600 opacity-0 group-hover:opacity-100 transition-opacity"
                      title="Copy Email"
                    >
                      {copiedField === 'email' ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                    </button>
                  </div>
                  <span className="bg-slate-100 border border-l-0 border-slate-200 rounded-r px-3 py-2 text-sm text-slate-500">@{config.school.domain}</span>
                </div>
              </div>
            </div>
          </section>

          <section>
            <label className="text-sm font-semibold text-slate-500 uppercase tracking-wider block mb-4">School Choice</label>
            <select 
              className="w-full border border-slate-200 rounded px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
              onChange={e => {
                const school = SCHOOL_PRESETS.find(s => s.id === e.target.value);
                if (school) setConfig({ ...config, school });
              }}
              value={config.school.id}
            >
              {SCHOOL_PRESETS.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
            </select>
          </section>

          <section>
            <label className="text-sm font-semibold text-slate-500 uppercase tracking-wider block mb-4">Letter Info</label>
            <div className="space-y-4">
              <div>
                <label className="text-xs text-slate-400 block mb-1">Document Date</label>
                <input 
                  type="text" 
                  value={config.date}
                  onChange={e => setConfig({ ...config, date: e.target.value })}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-sm"
                />
              </div>
              <div>
                <label className="text-xs text-slate-400 block mb-1">Employment Status</label>
                <input 
                  type="text" 
                  value={config.status}
                  onChange={e => setConfig({ ...config, status: e.target.value })}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-sm"
                />
              </div>
              <div>
                <label className="text-xs text-slate-400 block mb-1">Principal Signatory</label>
                <input 
                  type="text" 
                  value={config.principalName}
                  onChange={e => setConfig({ ...config, principalName: e.target.value })}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-sm"
                />
              </div>
            </div>
          </section>

          <div className="pt-6 grid grid-cols-2 gap-3 border-t border-slate-100">
            <button 
              onClick={downloadPDF}
              className="flex items-center justify-center gap-2 bg-slate-800 text-white px-4 py-2.5 rounded-lg text-sm font-semibold hover:bg-slate-900 transition-all shadow-sm"
            >
              <Download className="w-4 h-4" /> PDF
            </button>
            <button 
              onClick={downloadPNG}
              className="flex items-center justify-center gap-2 bg-blue-600 text-white px-4 py-2.5 rounded-lg text-sm font-semibold hover:bg-blue-700 transition-all shadow-sm"
            >
              <Download className="w-4 h-4" /> PNG
            </button>
          </div>
        </div>
      </div>

      {/* Letter Preview Container */}
      <div className="flex-1 p-8 flex justify-center items-start overflow-y-auto">
        <div 
          id="verification-letter"
          ref={letterRef}
          className="w-[210mm] min-h-[297mm] bg-white shadow-2xl p-[1.5in] letter-content text-[11pt] leading-relaxed text-slate-900 origin-top transform"
        >
          {/* Header */}
          <div className="border-b-2 border-slate-800 pb-2 mb-8 flex justify-between items-start">
            <div>
              <h2 className="text-2xl font-bold tracking-tight mb-2">{config.school.name}</h2>
              <div className="text-[9pt] text-slate-600 space-y-0.5">
                <p>{config.school.address}</p>
                <p>{config.school.cityStateZip}</p>
                <p>Phone: {config.school.phone} | Fax: {config.school.fax}</p>
              </div>
            </div>
            <div className="text-right text-[8pt] text-slate-500 font-medium">
              <p>{config.school.district}</p>
              {config.school.mascot && <p className="italic mt-1 uppercase font-bold text-slate-400">{config.school.mascot}</p>}
            </div>
          </div>

          {/* Letter Details */}
          <div className="mb-10">
            <p className="mb-6"><span className="font-bold border-b border-slate-800">Date:</span> {config.date}</p>
            <div className="mb-8">
              <p><span className="font-bold inline-block w-8">To:</span> SheerID Verification Department</p>
              <p><span className="font-bold inline-block w-8">Re:</span> Employment Status Confirmation</p>
            </div>
          </div>

          {/* Subject Header */}
          <div className="text-center mb-10">
            <h3 className="font-bold text-[12pt] underline decoration-1 underline-offset-4 uppercase">
              VERIFICATION OF EMPLOYMENT: {config.teacher.firstName} {config.teacher.lastName}
            </h3>
          </div>

          {/* Body */}
          <div className="space-y-6 text-justify">
            <p>To Whom It May Concern,</p>
            <p>
              This letter is to certify that <span className="font-bold">{config.teacher.prefix} {config.teacher.firstName} {config.teacher.lastName}</span> is currently employed with {config.school.district}, 
              serving as a full-time <span className="font-bold">Faculty Member</span> at {config.school.name}.
            </p>
            <p>
              {config.teacher.prefix} {config.teacher.lastName} is a teacher in good standing for the current academic year. {config.teacher.prefix === 'Mr.' ? 'His' : 'Her'} details are as follows:
            </p>

            <ul className="list-disc ml-12 space-y-1">
              <li><span className="font-bold">Employee Name:</span> {config.teacher.firstName} {config.teacher.lastName}</li>
              <li><span className="font-bold">Title:</span> {config.teacher.title}</li>
              <li><span className="font-bold">Location:</span> {config.school.name}</li>
              <li><span className="font-bold">Employment Status:</span> {config.status}</li>
            </ul>

            <p>
              This verification is provided at the request of the employee for the purpose of confirming eligibility for educational offers. 
              {config.teacher.prefix === 'Mr.' ? ' Mr.' : ' Ms.'} {config.teacher.lastName} has an active district email account ending in <span className="font-bold text-slate-800">@{config.school.domain}</span> and is fully authorized to access educational resources.
            </p>

            <p>
              If you require any further information regarding this employment verification, please feel free to contact the {config.school.district.split(' ')[0]} Human Resources office or the Main Office at {config.school.phone}.
            </p>

            <p>Sincerely,</p>
          </div>

          {/* Signature */}
          <div className="mt-16 pt-4">
            <div className="signature-font text-slate-800 mb-2" style={{ fontFamily: '"Alex Brush", cursive' }}>
              {config.principalName}
            </div>
            <div className="border-t border-slate-400 w-64 mb-4"></div>
            <div className="text-[10pt] space-y-0.5">
              <p className="font-bold">{config.principalPrefix} {config.principalName}</p>
              <p>Principal</p>
              <p>{config.school.name}</p>
              <p className="italic text-slate-500">Email: {config.principalName.split(' ')[0].toLowerCase().charAt(0)}{config.principalName.split(' ')[1].toLowerCase()}@{config.school.domain}</p>
            </div>
          </div>

          {/* Footer Subtext */}
          <div className="mt-auto pt-12 text-center text-[7pt] text-slate-400 italic">
            <p className="mb-1">{config.school.name} • {config.school.district} is an Equal Opportunity Employer.</p>
            {config.school.mascot && <p className="font-bold uppercase tracking-widest">{config.school.mascot}</p>}
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Copy, Download, RefreshCw, Check, Mail, User, Building, MapPin, Calendar, Briefcase } from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { LetterConfig, SchoolInfo, TeacherData } from './types';
import { SCHOOL_PRESETS, TEACHER_POOL } from './constants';

const App: React.FC = () => {
  const [config, setConfig] = useState<LetterConfig>({
    date: new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }),
    school: SCHOOL_PRESETS[0],
    teacher: TEACHER_POOL[0],
    principalName: 'Elizabeth McNamara',
    principalPrefix: 'Dr.',
    status: 'Active, Full-Time'
  });

  const [usedIndices, setUsedIndices] = useState<Set<number>>(new Set([0]));
  const [copiedField, setCopiedField] = useState<string | null>(null);
  const letterRef = useRef<HTMLDivElement>(null);

  const handleRandomize = () => {
    let nextIndex: number;
    if (usedIndices.size >= TEACHER_POOL.length) {
      setUsedIndices(new Set());
      nextIndex = Math.floor(Math.random() * TEACHER_POOL.length);
    } else {
      do {
        nextIndex = Math.floor(Math.random() * TEACHER_POOL.length);
      } while (usedIndices.has(nextIndex));
    }

    setUsedIndices(prev => new Set(prev).add(nextIndex));
    setConfig(prev => ({
      ...prev,
      teacher: TEACHER_POOL[nextIndex]
    }));
  };

  const handleCopy = (text: string, fieldName: string) => {
    navigator.clipboard.writeText(text);
    setCopiedField(fieldName);
    setTimeout(() => setCopiedField(null), 2000);
  };

  const downloadPNG = async () => {
    if (!letterRef.current) return;
    const canvas = await html2canvas(letterRef.current, { scale: 2 });
    const link = document.createElement('a');
    link.download = `${config.teacher.firstName}_${config.teacher.lastName}_Verification.png`;
    link.href = canvas.toDataURL('image/png');
    link.click();
  };

  const downloadPDF = async () => {
    if (!letterRef.current) return;
    const canvas = await html2canvas(letterRef.current, { scale: 2 });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const imgProps = pdf.getImageProperties(imgData);
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;
    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`${config.teacher.firstName}_${config.teacher.lastName}_Verification.pdf`);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center">
      {/* Editor Panel (Top) */}
      <div className="w-full max-w-5xl bg-white shadow-lg border-b border-slate-200">
        <div className="p-6 md:p-8">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
            <div className="flex items-center gap-2">
              <div className="bg-blue-600 p-2 rounded-lg">
                <Building className="text-white w-6 h-6" />
              </div>
              <h1 className="text-xl font-bold text-slate-800">EduVerify Pro</h1>
            </div>

            <div className="flex flex-wrap gap-3">
              <button 
                onClick={downloadPDF}
                className="flex items-center justify-center gap-2 bg-slate-800 text-white px-6 py-2 rounded-lg text-sm font-semibold hover:bg-slate-900 transition-all shadow-sm"
              >
                <Download className="w-4 h-4" /> PDF
              </button>
              <button 
                onClick={downloadPNG}
                className="flex items-center justify-center gap-2 bg-blue-600 text-white px-6 py-2 rounded-lg text-sm font-semibold hover:bg-blue-700 transition-all shadow-sm"
              >
                <Download className="w-4 h-4" /> PNG
              </button>
              <button 
                onClick={handleRandomize}
                className="flex items-center gap-2 text-sm font-medium text-blue-600 hover:text-blue-700 bg-blue-50 px-4 py-2 rounded-lg transition-colors border border-blue-100"
              >
                <RefreshCw className="w-4 h-4" /> Randomize Data
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {/* Teacher Details */}
            <section className="space-y-4">
              <label className="text-sm font-semibold text-slate-500 uppercase tracking-wider block border-b pb-2">Teacher Details</label>

              <div className="flex gap-2">
                <div className="w-24">
                  <label className="text-xs text-slate-400 block mb-1">Prefix</label>
                  <select 
                    value={config.teacher.prefix}
                    onChange={e => setConfig({ ...config, teacher: { ...config.teacher, prefix: e.target.value as any }})}
                    className="w-full border border-slate-200 rounded px-2 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50"
                  >
                    <option>Mr.</option>
                    <option>Ms.</option>
                    <option>Dr.</option>
                    <option>Mrs.</option>
                  </select>
                </div>
                <div className="flex-1">
                  <label className="text-xs text-slate-400 block mb-1">First Name</label>
                  <input 
                    type="text" 
                    value={config.teacher.firstName}
                    onChange={e => setConfig({ ...config, teacher: { ...config.teacher, firstName: e.target.value }})}
                    className="w-full border border-slate-200 rounded px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  />
                </div>
              </div>

              <div>
                <label className="text-xs text-slate-400 block mb-1">Last Name</label>
                <div className="relative group">
                  <input 
                    type="text" 
                    value={config.teacher.lastName}
                    onChange={e => setConfig({ ...config, teacher: { ...config.teacher, lastName: e.target.value }})}
                    className="w-full border border-slate-200 rounded px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  />
                  <button 
                    onClick={() => handleCopy(`${config.teacher.firstName} ${config.teacher.lastName}`, 'name')}
                    className="absolute right-2 top-2 p-1 text-slate-400 hover:text-blue-600"
                    title="Copy Full Name"
                  >
                    {copiedField === 'name' ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                </div>
              </div>

              <div>
                <label className="text-xs text-slate-400 block mb-1">Title</label>
                <input 
                  type="text" 
                  value={config.teacher.title}
                  onChange={e => setConfig({ ...config, teacher: { ...config.teacher, title: e.target.value }})}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </section>

            {/* School & Email */}
            <section className="space-y-4">
              <label className="text-sm font-semibold text-slate-500 uppercase tracking-wider block border-b pb-2">School & Contact</label>

              <div>
                <label className="text-xs text-slate-400 block mb-1">School Campus</label>
                <select 
                  className="w-full border border-slate-200 rounded px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50"
                  onChange={e => {
                    const school = SCHOOL_PRESETS.find(s => s.id === e.target.value);
                    if (school) setConfig({ ...config, school });
                  }}
                  value={config.school.id}
                >
                  {SCHOOL_PRESETS.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>

              <div>
                <label className="text-xs text-slate-400 block mb-1">Email Handle</label>
                <div className="relative group flex items-center">
                  <div className="flex-1 relative">
                    <input 
                      type="text" 
                      value={config.teacher.emailPrefix}
                      onChange={e => setConfig({ ...config, teacher: { ...config.teacher, emailPrefix: e.target.value }})}
                      className="w-full border border-slate-200 rounded-l px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                    <button 
                      onClick={() => handleCopy(`${config.teacher.emailPrefix}@${config.school.domain}`, 'email')}
                      className="absolute right-2 top-2 p-1 text-slate-400 hover:text-blue-600"
                      title="Copy Email"
                    >
                      {copiedField === 'email' ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                    </button>
                  </div>
                  <span className="bg-slate-100 border border-l-0 border-slate-200 rounded-r px-3 py-2 text-[10px] text-slate-500 font-mono">@{config.school.domain}</span>
