              <Building className="text-white w-6 h-6" />
            </div>
            <div>
              <h1 className="text-lg font-bold tracking-tight">EduVerify Pro</h1>
              <p className="text-[10px] text-slate-500 font-mono uppercase tracking-widest">Employment Verification Suite</p>
            </div>
          </div>
          <button 
            onClick={handleRandomize}
            className="flex items-center gap-2 text-xs font-semibold text-blue-400 hover:text-blue-300 bg-blue-500/10 hover:bg-blue-500/20 px-4 py-2 rounded-full transition-all border border-blue-500/20"
          >
            <RefreshCw className="w-3.5 h-3.5" /> Randomize Sample
          </button>
        </div>
      </header>

      {/* Control Panel (Editor) */}
      <div className="w-full max-w-5xl mt-8 px-6">
        <div className="bg-slate-900 border border-slate-800 rounded-2xl shadow-xl overflow-hidden">
          <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x divide-slate-800">
            {/* Column 1: Teacher */}
            <div className="p-6 space-y-5">
              <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                <span className="w-1 h-4 bg-blue-500 rounded-full"></span> Teacher Profile
              </h2>

              <div className="grid grid-cols-4 gap-2">
                <div className="col-span-1">
                  <label className="text-[10px] text-slate-500 block mb-1">Prefix</label>
                  <select 
                    value={config.teacher.prefix}
                    onChange={e => setConfig({ ...config, teacher: { ...config.teacher, prefix: e.target.value as any }})}
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg px-2 py-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none text-slate-200"
                  >
                    <option>Mr.</option><option>Ms.</option><option>Dr.</option><option>Mrs.</option>
                  </select>
                </div>
                <div className="col-span-3">
                  <label className="text-[10px] text-slate-500 block mb-1">First Name</label>
                  <input 
                    type="text" value={config.teacher.firstName}
