                    className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none"
                  />
                </div>
              </div>

              <div>
                <label className="text-[10px] text-slate-500 block mb-1">Last Name</label>
                <div className="relative group">
                  <input 
                    type="text" value={config.teacher.lastName}
                    onChange={e => setConfig({ ...config, teacher: { ...config.teacher, lastName: e.target.value }})}
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none pr-10"
                  />
                  <button 
                    onClick={() => handleCopy(`${config.teacher.firstName} ${config.teacher.lastName}`, 'name')}
                    className="absolute right-2 top-1.5 p-1.5 text-slate-500 hover:text-blue-400 transition-colors"
                  >
                    {copiedField === 'name' ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                </div>
              </div>

              <div>
                <label className="text-[10px] text-slate-500 block mb-1">Teacher Email</label>
                <div className="flex items-center">
                  <div className="flex-1 relative">
                    <input 
                      type="text" value={config.teacher.emailPrefix}
                      onChange={e => setConfig({ ...config, teacher: { ...config.teacher, emailPrefix: e.target.value }})}
                      className="w-full bg-slate-800 border border-slate-700 rounded-l-lg px-3 py-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none"
                    />
                    <button 
                      onClick={() => handleCopy(`${config.teacher.emailPrefix}@${config.school.domain}`, 'email')}
                      className="absolute right-2 top-1.5 p-1.5 text-slate-500 hover:text-blue-400"
                    >
                      {copiedField === 'email' ? <Check className="w-3.5 h-3.5 text-green-500" /> : <Copy className="w-3.5 h-3.5" />}
                    </button>
                  </div>
                  <span className="bg-slate-950 border border-l-0 border-slate-700 rounded-r-lg px-3 py-2 text-[11px] text-slate-400 font-mono">@{config.school.domain}</span>
                </div>
              </div>
            </div>

            {/* Column 2: School */}
            <div className="p-6 space-y-5">
              <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                <span className="w-1 h-4 bg-purple-500 rounded-full"></span> Campus Choice
              </h2>

              <div>
                <label className="text-[10px] text-slate-500 block mb-1">Select School</label>
                <select 
                  className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2.5 text-sm focus:ring-1 focus:ring-blue-500 outline-none"
                  onChange={e => {
                    const school = SCHOOL_PRESETS.find(s => s.id === e.target.value);
                    if (school) setConfig({ ...config, school });
