              <p className="text-[10px] text-slate-500 font-mono tracking-tighter uppercase">Employment Verification Suite</p>
            </div>
          </div>
          <button 
            onClick={handleRandomize}
            className="flex items-center gap-2 text-xs font-semibold text-indigo-400 hover:text-indigo-300 bg-indigo-500/10 px-4 py-2 rounded-full border border-indigo-500/20 transition-all active:scale-95"
