          <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 mb-2">
            <span className="w-1 h-4 bg-indigo-500 rounded-full"></span> Teacher Details
          </h2>
          <div className="grid grid-cols-4 gap-2">
            <select 
              value={config.teacher.prefix}
              onChange={e => setConfig({ ...config, teacher: { ...config.teacher, prefix: e.target.value as any }})}
              className="col-span-1 bg-slate-800 border border-slate-700 rounded-lg px-2 py-2 text-sm text-slate-200 outline-none focus:border-indigo-500"
            >
              <option>Mr.</option><option>Ms.</option><option>Dr.</option><option>Mrs.</option>
            </select>
            <input 
              type="text" placeholder="First Name" value={config.teacher.firstName}
