              className="col-span-3 bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-sm outline-none focus:border-indigo-500"
            />
          </div>
          <div className="relative">
            <input 
              type="text" placeholder="Last Name" value={config.teacher.lastName}
              onChange={e => setConfig({ ...config, teacher: { ...config.teacher, lastName: e.target.value }})}
              className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-sm outline-none pr-10 focus:border-indigo-500"
            />
            <button onClick={() => handleCopy(`${config.teacher.firstName} ${config.teacher.lastName}`, 'name')} className="absolute right-2 top-1.5 p-1.5 text-slate-500 hover:text-indigo-400">
              {copiedField === 'name' ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
            </button>
          </div>
          <div className="flex">
            <input 
