        </div>
      </header>

      <div className="w-full max-w-6xl mt-8 px-6 grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="bg-slate-900 border border-slate-800 rounded-xl p-6 space-y-4 shadow-xl">
          <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 mb-2">
            <span className="w-1 h-4 bg-indigo-500 rounded-full"></span> Personnel Data
          </h2>
          <div className="grid grid-cols-4 gap-2">
            <select 
              value={config.teacher.prefix}
