              className="col-span-1 bg-slate-800 border border-slate-700 rounded-lg px-1 py-2 text-sm text-slate-200 outline-none"
            >
              <option>Mr.</option><option>Ms.</option><option>Dr.</option><option>Mrs.</option>
            </select>
            <input 
              type="text" value={config.teacher.firstName}
              onChange={e => setConfig({ ...config, teacher: { ...config.teacher, firstName: e.target.value }})}
              className="col-span-3 bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-sm outline-none"
            />
          </div>
          <div className="relative">
            <input 
              type="text" value={config.teacher.lastName}
              onChange={e => setConfig({ ...config, teacher: { ...config.teacher, lastName: e.target.value }})}
              className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-sm outline-none pr-10"
            />
            <button onClick={() => handleCopy(`${config.teacher.firstName} ${config.teacher.lastName}`, 'name')} className="absolute right-2 top-1.5 p-1.5 text-slate-500 hover:text-indigo-400">
