          <div className="flex-none mb-[0.1in]">
            <div className="header-font flex justify-between items-start w-full">
              <div className="flex-1">
                <h1 className="text-[21pt] font-black tracking-tighter leading-[1.0] text-black">
                  {config.school.name}
                </h1>
                <div className="text-[10pt] leading-[1.3] mt-3 font-medium text-black">
                  <p>{config.school.address}</p>
                  <p>{config.school.cityStateZip}</p>
                  <p>Phone: {config.school.phone} | Fax: {config.school.fax}</p>
                </div>
              </div>
              <div className="text-right text-[10pt] font-bold leading-[1.1] pt-[0.2in] text-black">
                <p>Lincoln-Way Community</p>
                <p>High School District {config.school.district.match(/\d+/)?.[0] || '210'}</p>
              </div>
            </div>
            <div className="w-full h-[5px] bg-black mt-3"></div>
          </div>

          <div className="flex-grow letter-container pt-10">
            <div className="space-y-6">
              <p className="text-[12pt] text-black"><span className="font-bold">Date:</span> {config.date}</p>
              <div className="space-y-1 text-[12pt] text-black">
                <p><span className="font-bold">To:</span> SheerID Verification Department</p>
                <p><span className="font-bold">Re:</span> Employment Status Confirmation</p>
              </div>
            </div>

            <div className="text-center my-10">
              <p className="font-bold text-[12pt] text-black uppercase tracking-wide">
                <span className="underline decoration-1 underline-offset-[3px]">VERIFICATION OF EMPLOYMENT: {config.teacher.firstName.toUpperCase()} {config.teacher.lastName.toUpperCase()}</span>
              </p>
            </div>

            <div className="space-y-6 text-[12pt] text-black text-justify leading-[1.45]">
              <p>To Whom It May Concern,</p>
              <p>
                This letter is to certify that <span className="font-bold">{config.teacher.prefix} {config.teacher.firstName} {config.teacher.lastName}</span> is currently employed with {config.school.district}, 
                serving as a full-time <span className="font-bold">{config.teacher.title}</span> at {config.school.name.toUpperCase()}.
              </p>
              <p>
                {config.teacher.prefix} {config.teacher.lastName} is a teacher in good standing for the current academic year. Their details are as follows:
              </p>

              <ul className="ml-10 space-y-1 list-none">
                <li className="flex items-start gap-2">
                  <span className="text-[14pt] leading-[1.1]">•</span>
                  <span><span className="font-bold">Employee Name:</span> {config.teacher.firstName} {config.teacher.lastName}</span>
                </li>
                <li className="flex items-start gap-2">
                  <span className="text-[14pt] leading-[1.1]">•</span>
                  <span><span className="font-bold">Title:</span> {config.teacher.title}</span>
                </li>
                <li className="flex items-start gap-2">
                  <span className="text-[14pt] leading-[1.1]">•</span>
                  <span><span className="font-bold">Location:</span> {config.school.name.toUpperCase()}</span>
                </li>
                <li className="flex items-start gap-2">
                  <span className="text-[14pt] leading-[1.1]">•</span>
                  <span><span className="font-bold">Employment Status:</span> {config.status}</span>
                </li>
              </ul>

              <p>
                This verification is provided at the request of the employee for the purpose of confirming eligibility for educational offers. {config.teacher.prefix} {config.teacher.lastName} has an active district email account ending in <span className="font-bold">@{config.school.domain}</span> and is fully authorized to access educational resources.
              </p>

              <p>
                If you require any further information regarding this employment verification, please feel free to contact the Human Resources office or the Main Office at {config.school.phone}.
              </p>

              <p className="pt-2 pb-2">Sincerely,</p>
            </div>
          </div>

          <div className="flex-none pb-12 mt-4 relative">
            <div className="inline-block text-left">
              {/* Signature script area with controlled height to prevent overlap */}
              <div className="h-[40pt] flex items-end">
                <div className="signature-font text-[36pt] leading-none text-black pl-1 translate-y-[10px]">
                  {config.principalName}
                </div>
              </div>

              {/* Underline */}
              <div className="w-[3.6in] border-t-[1.5px] border-black my-2"></div>

              {/* Printed Name and Title */}
              <div className="text-[10pt] leading-[1.3] font-bold text-black letter-container">
                <p>{config.principalPrefix} {config.principalName}</p>
                <p className="font-normal text-[9.5pt]">Principal</p>
                <p className="font-normal text-[9.5pt]">{config.school.name.toUpperCase()}</p>
                <p className="font-normal text-[9.5pt]">Email: {principalEmailAddress}</p>
              </div>
            </div>
          </div>

          <div className="flex-none pt-2 pb-0">
            <div className="w-full border-t border-slate-300 mb-2"></div>
            <div className="text-center text-[8.5pt] text-slate-400 flex items-center justify-center gap-4 font-serif">
              <span className="uppercase font-bold tracking-[0.25em] text-slate-400 not-italic">
                {config.school.mascot || 'HOME OF THE KNIGHTS'}
              </span>
              <span className="w-[1px] h-3.5 bg-slate-300"></span>
              <span className="italic">
                {config.school.district} is an Equal Opportunity Employer.
              </span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
